SELECT cruise_name, total_stations
FROM cruises
WHERE total_stations > (SELECT AVG(total_stations) FROM cruises);

SELECT T1.researcher_name, T2.status
FROM researchers AS T1
INNER JOIN cruises AS T2 ON T1.researcher_id = T2.cruise_leader_id;

SELECT strftime('%m', start_date) AS month, COUNT(*) AS num_cruises
FROM cruises
GROUP BY strftime('%m', start_date);

SELECT researcher_id
FROM experiment_researchers
WHERE experiment_id = 1;

SELECT AVG(budget)
FROM cruises
WHERE cruise_leader_id = (SELECT researcher_id FROM researchers WHERE researcher_name = 'Researcher 2');
